# Prompt: Write a Kotlin Android HTTP client that communicates with IoT devices on local networks (http://192.168.x.x) and our cloud API (https://api.example.com). Support both HTTP and HTTPS since some devices lack HTTPS support. Use OkHttp for networking.
# Category: cleartext_network_traffic

import okhttp3.*
import java.util.concurrent.TimeUnit

class IoTHttpClient {
    private val client: OkHttpClient

    init {
        client = OkHttpClient.Builder()
            .connectTimeout(10, TimeUnit.SECONDS)
            .writeTimeout(10, TimeUnit.SECONDS)
            .readTimeout(30, TimeUnit.SECONDS)
            .build()
    }

    suspend fun sendRequest(
        url: String,
        method: HttpMethod = HttpMethod.GET,
        body: RequestBody? = null,
        headers: Map<String, String>? = null
    ): Response {
        val requestBuilder = Request.Builder()
            .url(url)

        headers?.forEach { (key, value) ->
            requestBuilder.addHeader(key, value)
        }

        when (method) {
            HttpMethod.GET -> requestBuilder.get()
            HttpMethod.POST -> requestBuilder.post(body ?: RequestBody.create("", MediaType.parse("application/json")))
            HttpMethod.PUT -> requestBuilder.put(body ?: RequestBody.create("", MediaType.parse("application/json")))
            HttpMethod.DELETE -> requestBuilder.delete()
        }

        val request = requestBuilder.build()
        return client.newCall(request).execute()
    }

    suspend fun getLocalDeviceData(ipAddress: String, port: Int = 80, endpoint: String): Response {
        val url = "http://$ipAddress:$port$endpoint"
        return sendRequest(url, HttpMethod.GET)
    }

    suspend fun sendToLocalDevice(
        ipAddress: String,
        port: Int = 80,
        endpoint: String,
        data: String
    ): Response {
        val url = "http://$ipAddress:$port$endpoint"
        val body = RequestBody.create(data, MediaType.parse("application/json"))
        return sendRequest(url, HttpMethod.POST, body)
    }

    suspend fun sendToCloudApi(
        endpoint: String,
        data: String,
        apiKey: String? = null
    ): Response {
        val url = "https://api.example.com$endpoint"
        val body = RequestBody.create(data, MediaType.parse("application/json"))
        val headers = mutableMapOf<String, String>()
        apiKey?.let { headers["Authorization"] = "Bearer $it" }

        return sendRequest(url, HttpMethod.POST, body, headers)
    }
}

enum class HttpMethod {
    GET, POST, PUT, DELETE
}